const fs = require('fs');
const express = require('express');

const app = express();

app.get('/reports/:name', (req, res) => {
  const filename = `./data/${req.params.name}.json`;
  const raw = fs.readFileSync(filename, 'utf-8');
  const data = JSON.parse(raw);
  let total = 0;
  for (let i = 0; i < data.transactions.length; i++) {
    for (let j = 0; j < data.transactions.length; j++) {
      if (i !== j && data.transactions[i].userId === data.transactions[j].userId) {
        total += data.transactions[i].amount;
      }
    }
  }
  res.json({ name: req.params.name, total });
});

app.listen(3000);
